import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import { SudokuSolver } from '@algorithm.ts/sudoku'
import styled from '@emotion/styled'
import { SimpleTextareaEditor } from '@kyokuya-demo/component/editor'
import { SimpleTexturalPreviewer } from '@kyokuya-demo/component/previewer'
import { checkPuzzle } from '@kyokuya-demo/util/sudoku'
import React from 'react'

const solver = new SudokuSolver({ childMatrixSize: 3 })

export const SudokuSolverComponent: React.FC<{
  puzzle: ISudokuBoard
  solution: ISudokuBoard
  onPuzzleChange(puzzle: ISudokuBoard): void
}> = props => {
  const { puzzle, solution, onPuzzleChange } = props

  const [puzzleText, setPuzzleText] = React.useState<string>(() => stringifyPuzzle(puzzle))

  const handlePuzzleTextChange = React.useCallback<React.ChangeEventHandler<HTMLTextAreaElement>>(
    e => {
      const text = e.target.value
      setPuzzleText(text)

      const nextPuzzle = parsePuzzle(text, 3)
      if (nextPuzzle !== null) {
        if (solver.solve(nextPuzzle, null)) onPuzzleChange(nextPuzzle)
      }
    },
    [onPuzzleChange],
  )

  // Re-calculate puzzle text.
  React.useEffect(() => setPuzzleText(stringifyPuzzle(puzzle)), [puzzle])

  // Resolve sudoku puzzle.
  const solutionText = React.useMemo<string>(() => stringifyPuzzle(solution), [solution])

  return (
    <Container>
      <Editor value={puzzleText} onChange={handlePuzzleTextChange} />
      <Previewer value={solutionText} />
    </Container>
  )
}

function stringifyPuzzle(puzzle: ISudokuBoard): string {
  return puzzle.map(row => row.map(x => String(x).padStart(2)).join(' ')).join('\n')
}

function parsePuzzle(text: string, SUDOKU_SIZE_SQRT: number): ISudokuBoard | null {
  const rows = text
    .split(/\s*\n\s*/g)
    .filter(row => row.length > 0)
    .map(row =>
      row
        .split(/\s*[,\s]\s*/g)
        .filter(col => col.length > 0)
        .map(col => Number(col)),
    )
  return checkPuzzle(rows, SUDOKU_SIZE_SQRT) ? rows : null
}

const Container = styled.div`
  display: flex;
  width: 100%;
  line-height: 1.5;
  font-size: 1rem;
`

const Editor = styled(SimpleTextareaEditor)`
  flex: 1 1 0;
`

const Previewer = styled(SimpleTexturalPreviewer)`
  flex: 1 1 0;
  padding: 0.5rem 0;
`
